import "sort"

// SuffixTree counts distinct substrings using suffix array and LCP.
func SuffixTree(arr []int) int {
	n := len(arr)
	if n == 0 {
		return 0
	}
	sa := make([]int, n)
	rank := make([]int, n)
	tmp := make([]int, n)
	for i := 0; i < n; i++ {
		sa[i] = i
		rank[i] = arr[i]
	}
	for k := 1; k < n; k *= 2 {
		r := make([]int, n)
		copy(r, rank)
		step := k
		sort.Slice(sa, func(i, j int) bool {
			a, b := sa[i], sa[j]
			if r[a] != r[b] {
				return r[a] < r[b]
			}
			ra, rb := -1, -1
			if a+step < n { ra = r[a+step] }
			if b+step < n { rb = r[b+step] }
			return ra < rb
		})
		tmp[sa[0]] = 0
		for i := 1; i < n; i++ {
			tmp[sa[i]] = tmp[sa[i-1]]
			p0, c0 := r[sa[i-1]], r[sa[i]]
			p1, c1 := -1, -1
			if sa[i-1]+step < n { p1 = r[sa[i-1]+step] }
			if sa[i]+step < n { c1 = r[sa[i]+step] }
			if p0 != c0 || p1 != c1 { tmp[sa[i]]++ }
		}
		copy(rank, tmp)
		if rank[sa[n-1]] == n-1 { break }
	}
	invSa := make([]int, n)
	lcp := make([]int, n)
	for i := 0; i < n; i++ { invSa[sa[i]] = i }
	h := 0
	for i := 0; i < n; i++ {
		if invSa[i] > 0 {
			j := sa[invSa[i]-1]
			for i+h < n && j+h < n && arr[i+h] == arr[j+h] { h++ }
			lcp[invSa[i]] = h
			if h > 0 { h-- }
		} else { h = 0 }
	}
	total := n * (n + 1) / 2
	for _, v := range lcp { total -= v }
	return total
}

import java.util.*;

public class SuffixTree {
    public static int suffixTree(int[] arr) {
        int n = arr.length;
        if (n == 0) return 0;

        // Build suffix array
        Integer[] sa = new Integer[n];
        int[] rank = new int[n], tmp = new int[n];
        for (int i = 0; i < n; i++) { sa[i] = i; rank[i] = arr[i]; }
        for (int k = 1; k < n; k *= 2) {
            final int[] r = rank.clone();
            final int step = k;
            Arrays.sort(sa, (a, b) -> {
                if (r[a] != r[b]) return Integer.compare(r[a], r[b]);
                int ra = a + step < n ? r[a + step] : -1;
                int rb = b + step < n ? r[b + step] : -1;
                return Integer.compare(ra, rb);
            });
            tmp[sa[0]] = 0;
            for (int i = 1; i < n; i++) {
                tmp[sa[i]] = tmp[sa[i - 1]];
                int p0 = r[sa[i-1]], c0 = r[sa[i]];
                int p1 = sa[i-1]+step<n ? r[sa[i-1]+step] : -1;
                int c1 = sa[i]+step<n ? r[sa[i]+step] : -1;
                if (p0 != c0 || p1 != c1) tmp[sa[i]]++;
            }
            System.arraycopy(tmp, 0, rank, 0, n);
            if (rank[sa[n-1]] == n-1) break;
        }

        // Build LCP (Kasai's)
        int[] invSa = new int[n], lcp = new int[n];
        for (int i = 0; i < n; i++) invSa[sa[i]] = i;
        int h = 0;
        for (int i = 0; i < n; i++) {
            if (invSa[i] > 0) {
                int j = sa[invSa[i] - 1];
                while (i+h < n && j+h < n && arr[i+h] == arr[j+h]) h++;
                lcp[invSa[i]] = h;
                if (h > 0) h--;
            } else { h = 0; }
        }

        long total = (long)n * (n + 1) / 2;
        for (int v : lcp) total -= v;
        return (int)total;
    }
}

fun suffixTree(arr: IntArray): Int {
    val n = arr.size
    if (n == 0) return 0
    val sa = Array(n) { it }
    var rank = arr.clone()
    val tmp = IntArray(n)
    var k = 1
    while (k < n) {
        val r = rank.clone(); val step = k
        sa.sortWith(Comparator { a, b ->
            if (r[a] != r[b]) return@Comparator r[a] - r[b]
            val ra = if (a + step < n) r[a + step] else -1
            val rb = if (b + step < n) r[b + step] else -1
            ra - rb
        })
        tmp[sa[0]] = 0
        for (i in 1 until n) {
            tmp[sa[i]] = tmp[sa[i - 1]]
            val p0 = r[sa[i-1]]; val c0 = r[sa[i]]
            val p1 = if (sa[i-1]+step<n) r[sa[i-1]+step] else -1
            val c1 = if (sa[i]+step<n) r[sa[i]+step] else -1
            if (p0 != c0 || p1 != c1) tmp[sa[i]]++
        }
        rank = tmp.clone()
        if (rank[sa[n-1]] == n-1) break
        k *= 2
    }
    val invSa = IntArray(n)
    val lcp = IntArray(n)
    for (i in 0 until n) invSa[sa[i]] = i
    var h = 0
    for (i in 0 until n) {
        if (invSa[i] > 0) {
            val j = sa[invSa[i]-1]
            while (i+h < n && j+h < n && arr[i+h] == arr[j+h]) h++
            lcp[invSa[i]] = h
            if (h > 0) h--
        } else { h = 0 }
    }
    return n * (n + 1) / 2 - lcp.sum()
}

def suffix_tree(arr: list[int]) -> int:
    n = len(arr)
    if n == 0:
        return 0

    # Build suffix array
    sa = list(range(n))
    rank = arr[:]
    tmp = [0] * n
    k = 1
    while k < n:
        def cmp_key(i, r=rank[:], step=k):
            return (r[i], r[i + step] if i + step < n else -1)
        sa.sort(key=cmp_key)
        tmp[sa[0]] = 0
        for i in range(1, n):
            tmp[sa[i]] = tmp[sa[i - 1]]
            if cmp_key(sa[i]) != cmp_key(sa[i - 1]):
                tmp[sa[i]] += 1
        rank = tmp[:]
        if rank[sa[-1]] == n - 1:
            break
        k *= 2

    # Build LCP array using Kasai's algorithm
    inv_sa = [0] * n
    for i in range(n):
        inv_sa[sa[i]] = i
    lcp = [0] * n
    h = 0
    for i in range(n):
        if inv_sa[i] > 0:
            j = sa[inv_sa[i] - 1]
            while i + h < n and j + h < n and arr[i + h] == arr[j + h]:
                h += 1
            lcp[inv_sa[i]] = h
            if h > 0:
                h -= 1
        else:
            h = 0

    total = n * (n + 1) // 2 - sum(lcp)
    return total

pub fn suffix_tree(arr: &[i32]) -> i32 {
    let n = arr.len();
    if n == 0 { return 0; }

    let mut sa: Vec<usize> = (0..n).collect();
    let mut rank: Vec<i64> = arr.iter().map(|&x| x as i64).collect();
    let mut tmp = vec![0i64; n];
    let mut k = 1;
    while k < n {
        let r = rank.clone();
        let step = k;
        sa.sort_by(|&a, &b| {
            let c = r[a].cmp(&r[b]);
            if c != std::cmp::Ordering::Equal { return c; }
            let ra = if a+step<n { r[a+step] } else { -1 };
            let rb = if b+step<n { r[b+step] } else { -1 };
            ra.cmp(&rb)
        });
        tmp[sa[0]] = 0;
        for i in 1..n {
            tmp[sa[i]] = tmp[sa[i-1]];
            let p0 = r[sa[i-1]]; let c0 = r[sa[i]];
            let p1 = if sa[i-1]+step<n { r[sa[i-1]+step] } else { -1 };
            let c1 = if sa[i]+step<n { r[sa[i]+step] } else { -1 };
            if p0 != c0 || p1 != c1 { tmp[sa[i]] += 1; }
        }
        rank = tmp.clone();
        if rank[sa[n-1]] == n as i64 - 1 { break; }
        k *= 2;
    }

    let mut inv_sa = vec![0usize; n];
    let mut lcp = vec![0i64; n];
    for i in 0..n { inv_sa[sa[i]] = i; }
    let mut h: usize = 0;
    for i in 0..n {
        if inv_sa[i] > 0 {
            let j = sa[inv_sa[i]-1];
            while i+h < n && j+h < n && arr[i+h] == arr[j+h] { h += 1; }
            lcp[inv_sa[i]] = h as i64;
            if h > 0 { h -= 1; }
        } else { h = 0; }
    }

    let total: i64 = n as i64 * (n as i64 + 1) / 2 - lcp.iter().sum::<i64>();
    total as i32
}

object SuffixTree {
  def suffixTree(arr: Array[Int]): Int = {
    val n = arr.length
    if (n == 0) return 0
    var sa = Array.tabulate(n)(identity)
    var rank = arr.clone()
    val tmp = new Array[Int](n)
    var k = 1
    while (k < n) {
      val r = rank.clone(); val step = k
      sa = sa.sortWith((a, b) => {
        if (r(a) != r(b)) r(a) < r(b)
        else {
          val ra = if (a+step<n) r(a+step) else -1
          val rb = if (b+step<n) r(b+step) else -1
          ra < rb
        }
      })
      tmp(sa(0)) = 0
      for (i <- 1 until n) {
        tmp(sa(i)) = tmp(sa(i-1))
        val p0 = r(sa(i-1)); val c0 = r(sa(i))
        val p1 = if (sa(i-1)+step<n) r(sa(i-1)+step) else -1
        val c1 = if (sa(i)+step<n) r(sa(i)+step) else -1
        if (p0 != c0 || p1 != c1) tmp(sa(i)) += 1
      }
      rank = tmp.clone()
      if (rank(sa(n-1)) == n-1) { k = n }
      else k *= 2
    }
    val invSa = new Array[Int](n)
    val lcp = new Array[Int](n)
    for (i <- 0 until n) invSa(sa(i)) = i
    var h = 0
    for (i <- 0 until n) {
      if (invSa(i) > 0) {
        val j = sa(invSa(i)-1)
        while (i+h < n && j+h < n && arr(i+h) == arr(j+h)) h += 1
        lcp(invSa(i)) = h
        if (h > 0) h -= 1
      } else { h = 0 }
    }
    n * (n + 1) / 2 - lcp.sum
  }
}

func suffixTree(_ arr: [Int]) -> Int {
    let n = arr.count
    if n == 0 { return 0 }
    var sa = Array(0..<n)
    var rank = arr
    var tmp = [Int](repeating: 0, count: n)
    var k = 1
    while k < n {
        let r = rank; let step = k
        sa.sort { a, b in
            if r[a] != r[b] { return r[a] < r[b] }
            let ra = a+step<n ? r[a+step] : -1
            let rb = b+step<n ? r[b+step] : -1
            return ra < rb
        }
        tmp[sa[0]] = 0
        for i in 1..<n {
            tmp[sa[i]] = tmp[sa[i-1]]
            let p0 = r[sa[i-1]], c0 = r[sa[i]]
            let p1 = sa[i-1]+step<n ? r[sa[i-1]+step] : -1
            let c1 = sa[i]+step<n ? r[sa[i]+step] : -1
            if p0 != c0 || p1 != c1 { tmp[sa[i]] += 1 }
        }
        rank = tmp
        if rank[sa[n-1]] == n-1 { break }
        k *= 2
    }
    var invSa = [Int](repeating: 0, count: n)
    var lcp = [Int](repeating: 0, count: n)
    for i in 0..<n { invSa[sa[i]] = i }
    var h = 0
    for i in 0..<n {
        if invSa[i] > 0 {
            let j = sa[invSa[i]-1]
            while i+h < n && j+h < n && arr[i+h] == arr[j+h] { h += 1 }
            lcp[invSa[i]] = h
            if h > 0 { h -= 1 }
        } else { h = 0 }
    }
    return n * (n + 1) / 2 - lcp.reduce(0, +)
}

export function suffixTree(arr: number[]): number {
    const n = arr.length;
    if (n === 0) return 0;

    const sa = Array.from({ length: n }, (_, i) => i);
    let rank = [...arr];
    const tmp = new Array(n);
    for (let k = 1; k < n; k *= 2) {
        const r = [...rank];
        const step = k;
        sa.sort((a, b) => {
            if (r[a] !== r[b]) return r[a] - r[b];
            const ra = a + step < n ? r[a + step] : -1;
            const rb = b + step < n ? r[b + step] : -1;
            return ra - rb;
        });
        tmp[sa[0]] = 0;
        for (let i = 1; i < n; i++) {
            tmp[sa[i]] = tmp[sa[i - 1]];
            const p0 = r[sa[i-1]], c0 = r[sa[i]];
            const p1 = sa[i-1]+step<n ? r[sa[i-1]+step] : -1;
            const c1 = sa[i]+step<n ? r[sa[i]+step] : -1;
            if (p0 !== c0 || p1 !== c1) tmp[sa[i]]++;
        }
        rank = [...tmp];
        if (rank[sa[n-1]] === n-1) break;
    }

    const invSa = new Array(n);
    const lcp = new Array(n).fill(0);
    for (let i = 0; i < n; i++) invSa[sa[i]] = i;
    let h = 0;
    for (let i = 0; i < n; i++) {
        if (invSa[i] > 0) {
            const j = sa[invSa[i]-1];
            while (i+h < n && j+h < n && arr[i+h] === arr[j+h]) h++;
            lcp[invSa[i]] = h;
            if (h > 0) h--;
        } else { h = 0; }
    }

    let total = n * (n + 1) / 2;
    for (const v of lcp) total -= v;
    return total;
}
